// Extract the incoming WhatsApp message from Meta's webhook payload.
// Meta also sends status update events (delivered, read, etc.).
// We return [] for those so the workflow stops — no greeting needed.

const body = $input.first().json.body;

// Stop if this is not a message event
if (!body?.entry?.[0]?.changes?.[0]?.value?.messages) {
  return [];
}

const value   = body.entry[0].changes[0].value;
const message = value.messages[0];
const contact = value.contacts?.[0];

// Only handle text messages here. Button replies go to later flows.
if (message.type !== 'text') {
  return [];
}

return [{
  json: {
    from:          message.from,
    messageId:     message.id,
    messageText:   message.text?.body || '',
    customerName:  contact?.profile?.name || 'there',
    phoneNumberId: value.metadata.phone_number_id,
    timestamp:     message.timestamp
  }
}];

// Build the WhatsApp interactive button message payload for the JERRYTECH greeting.
// Button titles must be ≤20 characters each.

const { from, customerName, phoneNumberId } = $input.first().json;

const payload = {
  messaging_product: 'whatsapp',
  recipient_type:    'individual',
  to:                from,
  type:              'interactive',
  interactive: {
    type: 'button',
    body: {
      text: `Hi ${customerName}! 👋 Welcome to *JERRYTECH Phone Repairs*. 📱\n\nWe fix phones fast & affordably.\nHow can we help you today?`
    },
    footer: {
      text: 'Tap a button below to get started'
    },
    action: {
      buttons: [
        { type: 'reply', reply: { id: 'book_appointment', title: 'Book Appointment'   } },
        { type: 'reply', reply: { id: 'check_status',     title: 'Check Repair Status' } },
        { type: 'reply', reply: { id: 'get_quote',        title: 'Get a Quote'         } }
      ]
    }
  }
};

return [{ json: { phoneNumberId, payload } }];
